ALTER TABLE `SecurityEvent` ADD CONSTRAINT `SecurityEvent_accountId_fkey` FOREIGN KEY (`accountId`) REFERENCES `UserAccount`(`id`) ON DELETE CASCADE ON UPDATE CASCADE;
